sys_script_email.script:
(function runMailScript(current, template, email, email_action, event) {
    template.print('<table border="1" style="border-collapse: collapse; width: 100%;">');
    template.print('<tr><th style="text-align: left; padding: 8px; background-color: #f2f2f2;">Variable</th><th style="text-align: left; padding: 8px; background-color: #f2f2f2;">Value</th></tr>');

    // Get all filled-in variables for the RITM
    var varOwn = new GlideRecord('sc_item_option_mtom');
    varOwn.addQuery('request_item', current.sys_id);
    varOwn.orderBy('sc_item_option.order');
    varOwn.query();

    while (varOwn.next()) {
        var label = varOwn.sc_item_option.item_option_new.question_text;
        var value = current.variables[varOwn.sc_item_option.item_option_new.name].getDisplayValue();

        if (value != '' && value != 'false') { // Only show non-empty variables
            template.print('<tr><td style="padding: 8px;">' + label + '</td><td style="padding: 8px;">' + value + '</td></tr>');
        }
    }
    template.print('</table>');
})(current, template, email, email_action, event);
